// getAuthenticatedUser retrieves the user from a valid session token
// Role is ALWAYS retrieved from the server-side authoritative store, never from client
func (gs *GameServer) getAuthenticatedUser(token string) (*User, error) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()

	session, exists := gs.sessions[token]
	if !exists {
		return nil, fmt.Errorf("invalid session")
	}

	if time.Now().After(session.ExpiresAt) {
		return nil, fmt.Errorf("session expired")
	}

	user, exists := gs.users[session.UserID]
	if !exists {
		return nil, fmt.Errorf("user not found")
	}

	// Check if user is banned
	if reason, banned := gs.banList[user.ID]; banned {
		return nil, fmt.Errorf("user is banned: %s", reason)
	}

	return user, nil
}

// hasPermission checks if a role has permission for a specific command
func hasPermission(role Role, command string) bool {
	permissions := map[string]Role{
		"/kick":      RoleModerator,
		"/ban":       RoleAdmin,
		"/unban":     RoleAdmin,
		"/giveitems": RoleAdmin,
		"/mute":      RoleModerator,
		"/announce":  RoleModerator,
		"/shutdown":  RoleSuperAdmin,
		"/setrole":   RoleSuperAdmin,
	}

	requiredRole, exists := permissions[command]
	if !exists {
		return false
	}

	return role >= requiredRole
}

