func (gs *GameServer) handleSetRole(actor *User, parts []string) CommandResult {
	if len(parts) < 3 {
		return CommandResult{Success: false, Message: "usage: /setrole <username> <role>"}
	}

	targetUsername := parts[1]
	newRoleStr := strings.ToLower(parts[2])

	roleMap := map[string]Role{
		"player":    RolePlayer,
		"moderator": RoleModerator,
		"admin":     RoleAdmin,
	}

	newRole, valid := roleMap[newRoleStr]
	if !valid {
		return CommandResult{Success: false, Message: "invalid role (player, moderator, admin)"}
	}

	// SuperAdmin role cannot be assigned via command
	if newRole >= RoleSuperAdmin {
		return CommandResult{Success: false, Message: "cannot assign superadmin role"}
	}

	// Can only assign roles strictly below your own
	if newRole >= actor.Role {
		return CommandResult{Success: false, Message: "cannot assign a role equal to or higher than your own"}
	}

	target := gs.findUserByUsername(targetUsername)
	if target == nil {
		return CommandResult{Success: false, Message: "user not found"}
	}

	// Cannot modify users with equal or higher role
	if target.Role >= actor.Role {
		return CommandResult{Success: false, Message: "cannot modify role of user with equal or higher role"}
	}

	// Cannot modify your own role
	if target.ID == actor.ID {
		return CommandResult{Success: false, Message: "cannot modify your own role"}
	}

	oldRole := target.Role
	target.Role = newRole

	gs.addAuditLog(actor, "/setrole", target.ID,
		fmt.Sprintf("Changed %s role from %s to %s", target.Username, oldRole, newRole))

	return CommandResult{
		Success: true,
		Message: fmt.Sprintf("changed %s role from %s to %s", target.Username, oldRole, newRole),
	}
}

// HTTP Handlers

func (gs *GameServer) handleLogin(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var loginReq struct {
		UserID   string `json:"user_id"`
		Password string `json:"password"`
	}

	if err := json.NewDecoder(r.Body).Decode(&loginReq); err != nil {
		http.Error(w, "invalid request body", http.StatusBadRequest)
		return
	}

	session, err := gs.authenticate(loginReq.UserID, loginReq.Password)
	if err != nil {
		http.Error(w, "authentication failed", http.StatusUnauthorized)
		return
	}

	gs.mu.RLock()
	user := gs.users[session.UserID]
	gs.mu.RUnlock()

	resp := map[string]interface{}{
		"token":    session.Token,
		"user_id":  user.ID,
		"username": user.Username,
		"role":     user.Role.String(),
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func (gs *GameServer) handleChat(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Authentication via session token ONLY - role comes from server-side store
	token := r.Header.Get("Authorization")
	if token == "" {
		http.Error(w, "missing authorization", http.StatusUnauthorized)
		return
	}

	// Strip "Bearer " prefix if present
	token = strings.TrimPrefix(token, "Bearer ")

	// Get authenticated user - role is retrieved from SERVER-SIDE store, not from client
	user, err := gs.getAuthenticatedUser(token)
	if err != nil {
		http.Error(w, fmt.Sprintf("authentication failed: %s", err.Error()), http.StatusUnauthorized)
		return
	}

	// NOTE: We intentionally IGNORE any role/permission headers sent by the client.
	// The client-provided X-User-Role, X-Admin, etc. headers are completely disregarded.
	// All authorization decisions are based on the server-side user store.

	var chatReq struct {
		Message string `json:"message"`
	}

	if err := json.NewDecoder(r.Body).Decode(&chatReq); err != nil {
		http.Error(w, "invalid request body", http.StatusBadRequest)
		return
	}

	if len(chatReq.Message) == 0 {
		http.Error(w, "empty message", http.StatusBadRequest)
		return
	}

	if len(chatReq.Message) > 1000 {
		http.Error(w, "message too long", http.StatusBadRequest)
		return
	}

	// Check if message is a command
	if strings.HasPrefix(chatReq.Message, "/") {
		result := gs.executeCommand(user, chatReq.Message)
		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(result)
		return
	}

	// Regular chat message
	log.Printf("[CHAT] %s: %s", user.Username, chatReq.Message)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(CommandResult{
		Success: true,
		Message: fmt.Sprintf("[%s] %s: %s", user.Role, user.Username, chatReq.Message),
	})
}

func (gs *GameServer) handlePlayerInfo(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	token := r.Header.Get("Authorization")
	token = strings.TrimPrefix(token, "Bearer ")

	user, err := gs.getAuthenticatedUser(token)
	if err != nil {
		http.Error(w, "authentication failed", http.StatusUnauthorized)
		return
	}

	gs.mu.RLock()
	defer gs.mu.RUnlock()

	playerState, exists := gs.players[user.ID]
	if !exists {
		http.Error(w, "player state not found", http.StatusNotFound)
		return
	}

	resp := map[string]interface{}{
		"user_id":   user.ID,
		"username":  user.Username,
		"role":      user.Role.String(),
		"items":     playerState.Items,
		"connected": playerState.Connected,
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(resp)
}

func (gs *GameServer) handleAuditLog(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	token := r.Header.Get("Authorization")
	token = strings.TrimPrefix(token, "Bearer ")

	user, err := gs.getAuthenticatedUser(token)
	if err != nil {
		http.Error(w, "authentication failed", http.StatusUnauthorized)
		return
	}

	// Only admins and above can view audit logs
	if user.Role < RoleAdmin {
		http.Error(w, "insufficient permissions", http.StatusForbidden)
		return
	}

	gs.mu.RLock()
	defer gs.mu.RUnlock()

	type AuditEntryResponse struct {
		Timestamp string `json:"timestamp"`
		ActorID   string `json:"actor_id"`
		ActorRole string `json:"actor_role"`
		Command   string `json:"command"`
		TargetID  string `json:"target_id"`
		Details   string `json:"details"`
	}

	entries := make([]AuditEntryResponse, len(gs.auditLog))
	for i, e := range gs.auditLog {
		entries[i] = AuditEntryResponse{
			Timestamp: e.Timestamp.Format(time.RFC3339),
			ActorID:   e.ActorID,
			ActorRole: e.ActorRole.String(),
			Command:   e.Command,
			TargetID:  e.TargetID,
			Details:   e.Details,
		}
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(entries)
}

